using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Uses constructor injection — the SDK resolves DI services automatically
/// and keeps them out of the tool's JSON schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1-100)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users with limit {Limit}", limit);
        var json = await httpClient.GetStringAsync($"/users?_limit={limit}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The user's numeric ID")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new user with the given name and email.")]
    public async Task<string> CreateUser(
        [Description("Full name of the user")] string name,
        [Description("Email address")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, email }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

